output.sparql:
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?placement WHERE {
  ?race wdt:P31 wd:Q7971574 ; wdt:P2781 "PT2H27M52S" ^^ xsd:duration . MINUS {
    ?race wdt:P2781 ?fasterTime .
    FILTER(?fasterTime < "PT2H27M52S" ^^ xsd:duration)
  }
  BIND(1 AS ?placement)
}

